mapper.insert:
INSERT INTO ORDER_MASTER (
      order_seq
    , user_seq
    , de_num
    , total_price
    , order_status
    , order_date
) VALUES (
      #{orderSeq}
    , #{userSeq}
    , #{deNum}
    , #{totalPrice}
    , #{orderStatus}
    , SYSDATE
)

INSERT INTO ORDER_DETAIL (
      detail_seq
    , order_seq
    , item_seq
    , quantity
    , unit_price
) VALUES (
      order_detail_seq.NEXTVAL
    , #{orderSeq}
    , #{itemSeq}
    , #{quantity}
    , #{unitPrice}
)
